export type PayrollDepartmentRecord = {
  id: string;
  name: string;
  manager: string;
  level: number;
  payrollCount: number;
  salaryTotal: number;
  averageSalary: number;
  commission: number;
  kpiPaid: number;
  attendanceDeduction: number;
  children?: PayrollDepartmentRecord[];
  details: {
    commission: Array<{ label: string; value: string }>;
    kpi: Array<{ label: string; value: string }>;
    attendance: Array<{ label: string; value: string }>;
  };
};

export type PayrollEmployeeRecord = {
  id: string;
  name: string;
  gender: "男" | "女";
  area: string;
  department: string;
  position: string;
  rank: string;
  hireDate: string;
  regularDate: string;
  expectedRegularDate?: string;
  resignationDate?: string;
  salaryTotal: number;
  salaryStructure: string;
  expectedAttendance: number;
  actualAttendance: number;
  leaveDays: number;
  leaveDetails: Array<{ label: string; value: string }>;
  lateCount: number;
  clockRepairCount: number;
  overtime: number;
  overtimeDetails: Array<{ label: string; value: string }>;
  kpiPaid: number;
  kpiDetails: Array<{ label: string; value: string }>;
  commissionPaid: number;
  remainingCommission: number;
  commissionDetails: Array<{ label: string; value: string }>;
  bonus: number;
  bonusDetails: Array<{ label: string; value: string }>;
  comprehensiveSubsidy: number;
  comprehensiveSubsidyDetails: Array<{ label: string; value: string }>;
  attendanceSubsidy: number;
  attendanceSubsidyDetails: Array<{ label: string; value: string }>;
  businessSubsidy: number;
  businessSubsidyDetails: Array<{ label: string; value: string }>;
  welfareSubsidy: number;
  attendanceDeduction: number;
  attendanceDeductionDetails: Array<{ label: string; value: string }>;
  otherDeduction: number;
  withholdingDeduction: number;
  withholdingDeductionDetails: Array<{ label: string; value: string }>;
  previousMonthDiff: number;
  remark: string;
  auditAdjustment: number;
  payableSalary: number;
};

export type PayrollApprovalInfo = {
  cycle: string;
  organization: string;
  submittedBy: string;
  submittedAt: string;
  departments: PayrollDepartmentRecord[];
  employees: PayrollEmployeeRecord[];
};

